public record Trade(String id, String instrument, double price, String status) {}

// Java 11+ Stream pipeline — functional, readable
List<Trade> trades = fetchTrades();

Map<String, Double> avgPriceByInstrument = trades.stream()
    .filter(t -> "COMPLETED".equals(t.status()))  // only completed trades
    .collect(Collectors.groupingBy(
        Trade::instrument,                          // group by instrument
        Collectors.averagingDouble(Trade::price)    // average the prices
    ));

// CompletableFuture — non-blocking async execution
CompletableFuture<Map<String, Double>> asyncResult =
    CompletableFuture.supplyAsync(() -> fetchTrades())  // fetch in background
        .thenApply(list -> list.stream()                // then process
            .filter(t -> "COMPLETED".equals(t.status()))
            .collect(Collectors.groupingBy(
                Trade::instrument,
                Collectors.averagingDouble(Trade::price)
            )));

// Java 21 Virtual Threads — handle 100k concurrent requests cheaply
try (var executor = Executors.newVirtualThreadPerTaskExecutor()) {
    executor.submit(() -> processTrade(trade));
}

