@RestController
@RequestMapping("/api/v1/portfolio")
@Validated
public class PortfolioController {

    private final PortfolioService portfolioService;

    // Constructor injection — always prefer this over @Autowired on field
    public PortfolioController(PortfolioService portfolioService) {
        this.portfolioService = portfolioService;
    }

    @GetMapping("/{userId}")
    @PreAuthorize("hasRole('USER') or @securityService.isSelf(#userId)")  // method-level security
    public ResponseEntity<PortfolioResponse> getPortfolio(
            @PathVariable @NotBlank String userId) {
        return ResponseEntity.ok(portfolioService.getPortfolio(userId));
    }

    @PostMapping
    public ResponseEntity<PortfolioResponse> create(
            @Valid @RequestBody CreatePortfolioRequest request) {  // @Valid triggers bean validation
        PortfolioResponse response = portfolioService.create(request);
        URI location = URI.create("/api/v1/portfolio/" + response.id());
        return ResponseEntity.created(location).body(response);
    }
}

