// Circuit Breaker with Resilience4j
@Service
public class InventoryClient {

    private final WebClient webClient;
    private final CircuitBreakerRegistry circuitBreakerRegistry;

    @CircuitBreaker(name = "inventory", fallbackMethod = "getInventoryFallback")
    @Retry(name = "inventory")    // retry 3 times before opening circuit
    @TimeLimiter(name = "inventory")  // timeout after 2 seconds
    public CompletableFuture<InventoryResponse> getInventory(String symbol) {
        return webClient.get()
            .uri("/inventory/{symbol}", symbol)
            .retrieve()
            .bodyToMono(InventoryResponse.class)
            .toFuture();
    }

    // Fallback: called when circuit is OPEN or all retries exhausted
    public CompletableFuture<InventoryResponse> getInventoryFallback(String symbol, Exception ex) {
        // Return cached/default data instead of failing the whole request
        return CompletableFuture.completedFuture(
            new InventoryResponse(symbol, 0, "UNAVAILABLE"));
    }
}

