@Configuration
public class KafkaProducerConfig {

    @Bean
    public ProducerFactory<String, TradeEvent> producerFactory() {
        Map<String, Object> props = new HashMap<>();
        props.put(ProducerConfig.BOOTSTRAP_SERVERS_CONFIG, "localhost:9092");
        props.put(ProducerConfig.KEY_SERIALIZER_CLASS_CONFIG, StringSerializer.class);
        props.put(ProducerConfig.VALUE_SERIALIZER_CLASS_CONFIG, JsonSerializer.class);
        props.put(ProducerConfig.ENABLE_IDEMPOTENCE_CONFIG, true);  // no duplicate sends
        props.put(ProducerConfig.ACKS_CONFIG, "all");  // wait for all replicas
        props.put(ProducerConfig.RETRIES_CONFIG, 3);
        return new DefaultKafkaProducerFactory<>(props);
    }
}

// Consumer with dead-letter queue handling
@KafkaListener(topics = "trade-events", groupId = "trade-processor")
public void processTradeEvent(@Payload TradeEvent event,
                               @Header(KafkaHeaders.RECEIVED_PARTITION) int partition,
                               Acknowledgment ack) {
    try {
        tradeService.process(event);
        ack.acknowledge();  // manually commit offset AFTER successful processing
    } catch (NonRetryableException ex) {
        // Send to DLT immediately — don't retry business logic errors
        kafkaTemplate.send("trade-events.DLT", event);
        ack.acknowledge();
    }
    // For retryable exceptions: don't ack — Kafka will redeliver
}

