// Token bucket rate limiter using Redis
@Service
public class RedisRateLimiter {

    private final StringRedisTemplate redis;
    private static final int MAX_REQUESTS = 100;  // per window
    private static final int WINDOW_SECONDS = 60;

    public boolean isAllowed(String userId) {
        String key = "rate:" + userId;
        // Lua script for atomic check-and-increment (no race conditions)
        String luaScript = """
            local current = redis.call('GET', KEYS[1])
            if current and tonumber(current) >= tonumber(ARGV[1]) then
                return 0  -- rate limit exceeded
            end
            local count = redis.call('INCR', KEYS[1])
            if count == 1 then
                redis.call('EXPIRE', KEYS[1], ARGV[2])  -- set TTL on first request
            end
            return 1  -- allowed
            """;
        Long result = redis.execute(
            new DefaultRedisScript<>(luaScript, Long.class),
            List.of(key),
            String.valueOf(MAX_REQUESTS), String.valueOf(WINDOW_SECONDS)
        );
        return Long.valueOf(1).equals(result);
    }
}

