// Thread-safe LRU Cache using LinkedHashMap
public class LRUCache<K, V> {

    private final int capacity;
    private final Map<K, V> cache;
    private final ReadWriteLock lock = new ReentrantReadWriteLock();

    public LRUCache(int capacity) {
        this.capacity = capacity;
        // LinkedHashMap with accessOrder=true: moves accessed entries to end
        this.cache = new LinkedHashMap<>(capacity, 0.75f, true) {
            @Override
            protected boolean removeEldestEntry(Map.Entry<K, V> eldest) {
                return size() > capacity;  // auto-evict when over capacity
            }
        };
    }

    public V get(K key) {
        lock.readLock().lock();
        try {
            V value = cache.get(key);  // also marks as recently used
            return value;
        } finally {
            lock.readLock().unlock();
        }
    }

    public void put(K key, V value) {
        lock.writeLock().lock();
        try {
            cache.put(key, value);
        } finally {
            lock.writeLock().unlock();
        }
    }
}

// Top K frequent using min-heap of size K
public class TopKTradedStocks {

    public List<String> topK(List<String> symbols, int k) {
        // Count frequency of each symbol
        Map<String, Integer> freq = new HashMap<>();
        for (String s : symbols) {
            freq.merge(s, 1, Integer::sum);
        }

        // Min-heap of size k: root = minimum frequency (next to evict)
        PriorityQueue<Map.Entry<String, Integer>> heap =
            new PriorityQueue<>(Comparator.comparingInt(Map.Entry::getValue));

        for (var entry : freq.entrySet()) {
            heap.offer(entry);
            if (heap.size() > k) {
                heap.poll();  // remove the LOWEST frequency entry
            }
        }

        // Remaining k entries are the top k
        List<String> result = new ArrayList<>();
        while (!heap.isEmpty()) {
            result.add(0, heap.poll().getKey());  // reverse order (highest first)
        }
        return result;
    }
}

// Sliding window rate limiter using deque per user
public class SlidingWindowRateLimiter {

    private final int maxRequests;
    private final long windowMillis;
    // ConcurrentHashMap for thread-safe per-user state
    private final ConcurrentHashMap<String, ArrayDeque<Long>> userWindows =
        new ConcurrentHashMap<>();

    public SlidingWindowRateLimiter(int maxRequests, Duration window) {
        this.maxRequests = maxRequests;
        this.windowMillis = window.toMillis();
    }

    public boolean isAllowed(String userId) {
        long now = System.currentTimeMillis();
        long windowStart = now - windowMillis;

        // computeIfAbsent is atomic — safe for concurrent first-time access
        ArrayDeque<Long> timestamps = userWindows.computeIfAbsent(
            userId, k -> new ArrayDeque<>());

        synchronized (timestamps) {  // synchronize on the deque for this user
            // Remove timestamps older than the window
            while (!timestamps.isEmpty() && timestamps.peekFirst() < windowStart) {
                timestamps.pollFirst();
            }
            if (timestamps.size() < maxRequests) {
                timestamps.addLast(now);  // record this request
                return true;  // allowed
            }
            return false;  // rate limit exceeded
        }
    }
}

