// Request DTO with validation
public record TransferRequest(
    @NotBlank String fromAccountId,
    @NotBlank String toAccountId,
    @NotNull @DecimalMin("0.01") BigDecimal amount,
    @NotBlank String currency
) {}

// Service with @Transactional and idempotency
@Service
public class TransferService {

    @Transactional
    public TransferResponse transfer(TransferRequest req, String idempotencyKey) {
        // Check idempotency: has this exact request been processed before?
        Optional<Transfer> existing = transferRepo.findByIdempotencyKey(idempotencyKey);
        if (existing.isPresent()) {
            return TransferResponse.from(existing.get());  // return cached result
        }

        // Lock both accounts in consistent order to prevent deadlock
        String lockOrder = req.fromAccountId().compareTo(req.toAccountId()) < 0
            ? req.fromAccountId() + req.toAccountId()
            : req.toAccountId() + req.fromAccountId();

        Account from = accountRepo.findByIdWithLock(req.fromAccountId());
        Account to = accountRepo.findByIdWithLock(req.toAccountId());

        if (from.getBalance().compareTo(req.amount()) < 0) {
            throw new InsufficientFundsException(req.fromAccountId());
        }

        from.debit(req.amount());
        to.credit(req.amount());

        Transfer transfer = new Transfer(req, idempotencyKey, TransferStatus.COMPLETED);
        transferRepo.save(transfer);
        // @Transactional commits here — both account updates + transfer record atomic

        return TransferResponse.from(transfer);
    }
}

// Thread-safe Observer for price alerts
@Service
public class PriceAlertService {

    // Map: symbol → list of alert subscriptions
    private final ConcurrentHashMap<String, List<PriceAlert>> alertsBySymbol =
        new ConcurrentHashMap<>();

    // Virtual thread executor — lightweight, scales to millions of notifications
    private final ExecutorService executor =
        Executors.newVirtualThreadPerTaskExecutor();

    // Subscribe: add a price alert
    public String subscribe(String symbol, String userId,
                            BigDecimal threshold, AlertType type) {
        PriceAlert alert = new PriceAlert(UUID.randomUUID().toString(),
                                          userId, threshold, type);
        alertsBySymbol.computeIfAbsent(symbol, k -> new CopyOnWriteArrayList<>())
                      .add(alert);
        return alert.alertId();
    }

    // Called when a new price tick arrives for a symbol
    public void onPriceUpdate(String symbol, BigDecimal newPrice) {
        List<PriceAlert> alerts = alertsBySymbol.getOrDefault(symbol, List.of());

        for (PriceAlert alert : alerts) {  // CopyOnWriteArrayList safe for concurrent iteration
            if (shouldTrigger(alert, newPrice)) {
                // Async notification — don't block the price feed thread
                executor.submit(() -> notifyUser(alert, symbol, newPrice));
            }
        }
    }

    private boolean shouldTrigger(PriceAlert alert, BigDecimal price) {
        return switch (alert.type()) {
            case ABOVE -> price.compareTo(alert.threshold()) >= 0;
            case BELOW -> price.compareTo(alert.threshold()) <= 0;
        };
    }
}
